import java.util.*;class BinarySearch4{static int first(int[] a,int t){int l=0,r=a.length-1,res=-1;while(l<=r){int m=(l+r)/2;if(a[m]==t){res=m;r=m-1;}else if(a[m]<t)l=m+1;else r=m-1;}return res;}static int last(int[] a,int t){int l=0,r=a.length-1,res=-1;while(l<=r){int m=(l+r)/2;if(a[m]==t){res=m;l=m+1;}else if(a[m]<t)l=m+1;else r=m-1;}return res;}public static void main(String[] x){Scanner s=new Scanner(System.in);int n=s.nextInt();int[] a=new int[n];for(int i=0;i<n;i++)a[i]=s.nextInt();int t=s.nextInt();System.out.println(first(a,t)+" "+last(a,t));}}